const parseTCSCsv = (text) => {
  const lines = text.trim().split("\n").filter(l => l.trim());
  if (lines.length < 2) return [];
  const header = lines[0].toLowerCase().split(",").map(h => h.trim().replace(/"/g, ""));
  return lines.slice(1).map(line => {
    const cols = line.split(",").map(c => c.trim().replace(/"/g, ""));
    const obj = {};
    header.forEach((h, i) => { obj[h] = cols[i] || ""; });
    const gallons = parseFloat(obj.gallons || obj.qty || obj.quantity || 0);
    const ppg = parseFloat(obj.ppg || obj.price || obj["unit price"] || 0);
    const total = parseFloat(obj.amount || obj.total || obj["net amount"] || (gallons * ppg) || 0);
    const date = obj.date || obj["trans date"] || obj["transaction date"] || "";
    const loc = obj.location || obj.site || obj.merchant || obj.store || "";
    const truck = obj.truck || obj.unit || obj.vehicle || obj["card #"] || "";
    if (!date || gallons === 0) return null;
    return { id: uid(), date, truckRaw: truck.trim(), gallons, price_per: ppg, total: Math.abs(total), location: loc, load_num: "" };
  }).filter(Boolean);
};

const printPaystub = (driver, driverLoads, period) => {
  const totalGross = driverLoads.reduce((s, l) => s + Number(l.rate || 0) + Number(l.detention || 0), 0);
  const totalPay = driverLoads.reduce((s, l) => { const g = Number(l.rate || 0) + Number(l.detention || 0); return s + g * (Number(l.driverPct || 0) / 100); }, 0);
  const totalMiles = driverLoads.reduce((s, l) => s + Number(l.miles || 0), 0);
  const totalDetention = driverLoads.reduce((s, l) => s + Number(l.detention || 0), 0);
  const w = window.open("", "_blank");
  w.document.write(`<html><head><title>Paystub - ${driver}</title><style>body{font-family:'Courier New',monospace;max-width:700px;margin:40px auto;color:#111}.header{text-align:center;border-bottom:3px solid #000;padding-bottom:20px;margin-bottom:20px}.company{font-size:28px;font-weight:900;letter-spacing:2px}.row{display:flex;justify-content:space-between;padding:4px 0;font-size:13px}.row.total{font-weight:900;font-size:16px;border-top:2px solid #000;margin-top:8px;padding-top:8px}.load-row{display:grid;grid-template-columns:1fr 1fr 1fr 1fr 1fr;gap:8px;padding:6px 0;border-bottom:1px solid #eee;font-size:12px}.section-title{font-weight:900;font-size:11px;letter-spacing:1.5px;text-transform:uppercase;border-bottom:1px solid #000;padding-bottom:4px;margin-bottom:10px;margin-top:20px}</style></head><body><div class="header"><div class="company">BHANDARI FLEET MANAGEMENT</div><div>DRIVER PAY STATEMENT</div></div><div class="row"><span>Driver:</span><span><b>${driver}</b></span></div><div class="row"><span>Period:</span><span>${period}</span></div><div class="row"><span>Total Loads:</span><span>${driverLoads.length}</span></div><div class="row"><span>Total Miles:</span><span>${fmtMi(totalMiles)}</span></div><div class="section-title">Load Detail</div>${driverLoads.map(l=>{const g=Number(l.rate||0)+Number(l.detention||0);const pay=g*(Number(l.driverPct||0)/100);return `<div class="load-row"><span>${l.loadNum}</span><span>${l.origin||''} to ${l.dest||''}</span><span>${fmtMi(l.miles)} mi</span><span>${fmt$(g)}</span><span>${fmt$(pay)}</span></div>`;}).join('')}<div class="section-title">Summary</div><div class="row"><span>Gross Revenue:</span><span>${fmt$(totalGross)}</span></div><div class="row"><span>Detention:</span><span>${fmt$(totalDetention)}</span></div><div class="row total"><span>TOTAL PAY:</span><span>${fmt$(totalPay)}</span></div><script>window.onload=()=>window.print();</script></body></html>`);
  w.document.close();
};

