const Field = ({ label, type = "text", value, onChange, options, span, placeholder }) => (<div style={{ display: "flex", flexDirection: "column", gap: 5, gridColumn: span ? "1 / -1" : undefined }}><label style={{ color: "#2d4a6a", fontSize: 10, fontWeight: 700, letterSpacing: 1, textTransform: "uppercase" }}>{label}</label>{options ? (<select value={value} onChange={e => onChange(e.target.value)} style={{ background: "#0c1a2e", border: "1px solid #1a3550", borderRadius: 8, color: "#e2e8f0", padding: "10px 12px", fontSize: 13 }}>{options.map(o => <option key={o.value ?? o} value={o.value ?? o}>{o.label ?? o}</option>)}</select>) : (<input type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder} style={{ background: "#0c1a2e", border: "1px solid #1a3550", borderRadius: 8, color: "#e2e8f0", padding: "10px 12px", fontSize: 13 }} />)}</div>);
