  const BT = { name: "", plate: "", year: "", make: "Kenworth", model: "", color: TRUCK_COLORS[3], active: true };
  const [lf, setLf] = useState(BL);
  const [ff, setFf] = useState(BF);
  const [ef, setEf] = useState(BE);
  const [tf, setTf] = useState(BT);

  const truckById = id => trucks.find(t => t.id === id);
  const truckOpts = trucks.map(t => ({ value: t.id, label: t.name }));
  const truckOptsAll = [{ value: "FLEET", label: "Fleet-wide" }, ...truckOpts];

  const openAdd = (m) => { const ft = trucks[0]?.id || ""; if (m === "load") setLf({ ...BL, truckId: ft }); if (m === "fuel") setFf({ ...BF, truckId: ft }); if (m === "expense") setEf(BE); if (m === "truck") setTf(BT); setEditId(null); setModal(m); };
  const openEdit = (m, item) => { if (m === "load") setLf({ ...item }); if (m === "fuel") setFf({ ...item }); if (m === "expense") setEf({ ...item }); if (m === "truck") setTf({ ...item }); setEditId(item.id); setModal(m); };
  const closeModal = () => { setModal(null); setEditId(null); setCsvRows([]); setCsvDone(false); };

  const saveLoad = async () => { if (!lf.loadNum || !lf.rate) return; setSaving(true); const row = { id: editId || uid(), date: lf.date, load_num: lf.loadNum, origin: lf.origin, dest: lf.dest, miles: Number(lf.miles), rate: Number(lf.rate), detention: Number(lf.detention), driver: lf.driver, driver_pct: Number(lf.driverPct), truck_id: lf.truckId, status: lf.status }; const { error } = await db.from("loads").upsert(row); if (error) showToast("Save failed", "error"); else { await fetchAll(); closeModal(); showToast(editId ? "Load updated" : "Load added"); } setSaving(false); };
  const saveFuel = async () => { const tot = Number(ff.total) || (Number(ff.gallons) * Number(ff.pricePer)); if (!ff.truckId || !tot) return; setSaving(true); const row = { id: editId || uid(), date: ff.date, truck_id: ff.truckId, gallons: Number(ff.gallons), price_per: Number(ff.pricePer), total: tot, location: ff.location, load_num: ff.loadNum }; const { error } = await db.from("fuel").upsert(row); if (error) showToast("Save failed", "error"); else { await fetchAll(); closeModal(); showToast("Fuel saved"); } setSaving(false); };
  const saveExp = async () => { if (!ef.description || !ef.amount) return; setSaving(true); const row = { id: editId || uid(), date: ef.date, truck_id: ef.truckId, category: ef.category, description: ef.description, amount: Number(ef.amount) }; const { error } = await db.from("expenses").upsert(row); if (error) showToast("Save failed", "error"); else { await fetchAll(); closeModal(); showToast("Expense saved"); } setSaving(false); };
  const saveTruck = async () => { if (!tf.name) return; setSaving(true); const row = { id: editId || ("T" + uid()), name: tf.name, plate: tf.plate, year: tf.year, make: tf.make, model: tf.model, color: tf.color, active: tf.active }; const { error } = await db.from("trucks").upsert(row); if (error) showToast("Save failed", "error"); else { await fetchAll(); closeModal(); showToast(editId ? "Truck updated" : "Truck added"); } setSaving(false); };
